import{_ as e,o as t,c as r,a3 as n}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"30A. Consultation About Changes To Rosters Or Hours Of Work","description":"","frontmatter":{"title":"30A. Consultation About Changes To Rosters Or Hours Of Work","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["hours","rosters","consultation","union-matters"]},"headers":[],"relativePath":"ebas/mspp/employment/30A-consultation-about-changes-to-rosters-or-hours-of-work.md","filePath":"ebas/mspp/employment/30A-consultation-about-changes-to-rosters-or-hours-of-work.md"}'),s={name:"ebas/mspp/employment/30A-consultation-about-changes-to-rosters-or-hours-of-work.md"};function a(i,o,p,h,c,l){return t(),r("div",null,[...o[0]||(o[0]=[n('<h1 id="_30a-consultation-about-changes-to-rosters-or-hours-of-work" tabindex="-1">30A. Consultation About Changes To Rosters Or Hours Of Work <a class="header-anchor" href="#_30a-consultation-about-changes-to-rosters-or-hours-of-work" aria-label="Permalink to &quot;30A. Consultation About Changes To Rosters Or Hours Of Work&quot;">​</a></h1><p>This clause 30A applies where a change to regular rosters or ordinary hours of work (which may impact upon an Employee, particularly in relation to their family and caring responsibilities) does not constitute ‘Major Change’ in accordance with subclause 30.2c.</p><p><strong>a.</strong> Where an Employer proposes to change an Employee’s regular roster or ordinary hours of work, the Employer must consult with the Employee or Employees affected and their Union or representatives, if any, about the proposed change.</p><p><strong>b.</strong> The Employer must:</p><p><strong>(i)</strong> consider health and safety impacts including workload and fatigue;</p><p><strong>(ii)</strong> provide to the Employee or Employees affected and their Union or representatives, if any, information about the proposed change (for example, information about the nature of the change to the Employee’s regular roster or ordinary hours of work, workload and when that change is proposed to commence);</p><p><strong>(iii)</strong> invite the Employee or Employees affected and their Union or representatives, if any, to give their views about the impact of the proposed change (including any impact in relation to their family or caring responsibilities); and</p><p>3453-8976-3100v1PART 4: EMPLOYMENT RELATIONSHIP AND RELATED ARRANGEMENTS</p><p><strong>(iv)</strong> give consideration to any views about the impact of the proposed change that is given by the Employee or Employees concerned and/or their representatives.</p><p><strong>c.</strong> The requirement to consult under this clause does not apply where an Employee has irregular, sporadic, unpredictable working hours or self- rostering.</p><p><strong>d.</strong> These provisions are to be read in conjunction with the terms of the engagement between the Employer and Employee, other Agreement provisions concerning the scheduling of work and notice requirements.</p><p>Plain language terms: roster consultation.</p>',12)])])}const g=e(s,[["render",a]]);export{m as __pageData,g as default};
